"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const cards=[['Context','What changed in the system'],['Witness','What the team observed'],['Outcome','What should happen next']];
export default function ScrollWitnessRail(){const [active,setActive]=useState(0);const reduced=useReducedMotion();const move=(delta:number)=>setActive((active+delta+cards.length)%cards.length);const key=(event:React.KeyboardEvent<HTMLDivElement>)=>{if(event.key==='ArrowLeft')move(-1);if(event.key==='ArrowRight')move(1);};return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">witness rail</p><div tabIndex={0} onKeyDown={key} aria-label="Evidence reading rail; use left and right arrows" className="mt-4 overflow-hidden rounded-2xl border border-[#ececee] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"><motion.div animate={{x:`-${active*100}%`}} transition={reduced?{duration:.12}:{type:'spring',stiffness:330,damping:28}} className="flex">{cards.map((card,index)=><article key={card[0]} className="w-full shrink-0 p-4"><span className="text-xs font-bold text-[#65a30d]">0{index+1}</span><h2 className="mt-1 text-lg font-black text-[#111]">{card[0]}</h2><p className="mt-1 text-sm text-[#4a4a4f]">{card[1]}</p></article>)}</motion.div></div><div className="mt-3 flex gap-2"><motion.button type="button" onClick={()=>move(-1)} whileTap={reduced?undefined:{y:1}} className="min-h-11 flex-1 rounded-xl border border-[#ececee] font-bold outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">Previous</motion.button><motion.button type="button" onClick={()=>move(1)} whileTap={reduced?undefined:{y:1}} className="min-h-11 flex-1 rounded-xl bg-[#111] font-bold text-white outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">Next</motion.button></div><div className="mt-3 h-1 rounded-full bg-[#f4f5f6]"><motion.i animate={{x:active*88}} transition={reduced?{duration:.12}:{type:'spring',stiffness:330,damping:28}} className="block h-1 w-8 rounded-full bg-[#65a30d]"/></div><p aria-live="polite" className="mt-2 text-xs text-[#4a4a4f]">Witnessing: {cards[active][0]}.</p></section>}
